// Open Pest Modal Detail inside Product Modal Overlay
window.openPestModal = function(pestId) {
    const pest = pestsData.find(p => p.id === pestId);
    if (!pest) return;
    
    const modal = document.getElementById("product-modal");
    const body = document.getElementById("modal-content-body");
    
    const symptomsBullets = pest.symptoms.map(s => `<li><i class="fa-solid fa-circle-minus" style="color: #ef4444; font-size: 0.8rem; margin-top: 5px;"></i> <div>${s}</div></li>`).join('');
    
    body.innerHTML = `
        <div class="modal-grid">
            <div class="modal-info-side">
                <h2>${pest.name}</h2>
                <div class="modal-alias" style="color: #f87171; font-weight: 600;"><i class="fa-solid fa-clock"></i> Gây hại: ${pest.stageTarget}</div>
                
                <div class="modal-desc-box" style="margin-top: 1.5rem;">
                    <h4 style="color: #f87171;"><i class="fa-solid fa-circle-exclamation"></i> Triệu Chứng Điển Hình:</h4>
                    <ul style="list-style: none; margin-bottom: 1.2rem; line-height: 1.6; padding-left: 0;">${symptomsBullets}</ul>
                </div>
                
                <div class="modal-desc-box" style="margin-top: 1.5rem;">
                    <h4 style="color: #70ad47;"><i class="fa-solid fa-shield-halved"></i> Biện Pháp Phòng Ngừa Kỹ Thuật:</h4>
                    <p style="font-size: 0.95rem; line-height: 1.6; color: #374151;">${pest.prevention}</p>
                </div>
            </div>

            <div class="modal-visual-side">
                <div class="modal-visual-container">
                    <img class="modal-packshot" src="${pest.image}" alt="${pest.name}" style="border-radius: 12px; max-height: 220px; object-fit: cover; border: 1px solid rgba(0,0,0,0.08);">
                </div>
                
                <div class="modal-desc-box" style="width: 100%; border-top: 1px solid rgba(0,0,0,0.08); padding-top: 1.5rem; margin-top: 1rem;">
                    <h4 style="color: #4ade80;"><i class="fa-solid fa-kit-medical"></i> Giải Pháp Đặc Trị:</h4>
                    <p style="background: rgba(74, 222, 128, 0.05); padding: 12px; border-radius: 8px; border-left: 3px solid #4ade80; font-size: 0.95rem; line-height: 1.5; font-weight: 500; color: #1f2937;">
                        ${pest.solution}
                    </p>
                    ${pest.productLink ? `
                        <button class="pest-card-btn" style="margin-top: 15px; width: 100%; text-align: center; display: block; padding: 10px; font-weight: 600;" onclick="openProductModal('${pest.productLink}')">
                            <i class="fa-solid fa-prescription-bottle-medical"></i> Xem Chi Tiết Thuốc Đặc Trị
                        </button>
                    ` : ''}
                </div>
            </div>
        </div>
    `;
    modal.classList.add("active");
};

