// Apply Combo selected in directory to calculator panel
window.applyComboToCalc = function(actionId) {
    let tabTarget = "retail";
    if (["capcheo", "combo3", "combo4", "combo5", "luanew_combo3", "luanew_combo4"].includes(actionId)) {
        tabTarget = "tri";
    } else if (["combo1", "combo2", "luanew_combo1", "luanew_combo2"].includes(actionId)) {
        tabTarget = "dinhduong";
    }
    
    const calcTabBtn = document.querySelector(`.calc-tab-btn[data-calc-tab="${tabTarget}"]`);
    if (calcTabBtn) {
        calcTabBtn.click();
    }

    const calcType = document.getElementById("calc-type");
    if (calcType) {
        calcType.value = actionId;
        // Trigger calculation
        calculatePricing();
        // Switch to calculator module
        switchModule("module-calculator");
        
        // Add a temporary highlight glow to the calculator results
        const calcCard = document.querySelector(".calculator-grid");
        if (calcCard) {
            calcCard.style.boxShadow = "0 0 25px rgba(74, 222, 128, 0.8)";
            setTimeout(() => {
                calcCard.style.boxShadow = "";
            }, 2000);
        }
    }
};

