// Toggle Accordion Panel
window.toggleAccordion = function(element) {
    const item = element.parentElement;
    const content = element.nextElementSibling;
    
    if (item.classList.contains("active")) {
        item.classList.remove("active");
        content.style.maxHeight = null;
    } else {
        item.classList.add("active");
        content.style.maxHeight = content.scrollHeight + "px";
    }
};

// Switch active training module (Dashboard Tabs logic)
window.switchModule = function(moduleId) {
    const modules = document.querySelectorAll(".dashboard-module");
    modules.forEach(m => m.classList.remove("active"));
    
    const target = document.getElementById(moduleId);
    if (target) {
        target.classList.add("active");
    }
    
    // Update active class on buttons
    const btns = document.querySelectorAll(".sidebar-nav-btn");
    btns.forEach(b => {
        if (b.getAttribute("data-target") === moduleId) {
            b.classList.add("active");
        } else {
            b.classList.remove("active");
        }
    });

    // Reset scroll top of view
    document.querySelector(".dashboard-viewport").scrollTop = 0;
};

// Pricing interpolations for retail F90
function getF90CasePriceAndGifts(qty) {
    const table = {
        1: { price: 7000000, gift: "10 chai Siêu dưỡng trái" },
        2: { price: 13500000, gift: "25 chai Siêu dưỡng trái" },
        3: { price: 19500000, gift: "40 chai Siêu dưỡng trái" },
        4: { price: 25000000, gift: "60 chai Siêu dưỡng trái" },
        5: { price: 30000000, gift: "80 chai Siêu dưỡng trái" },
        10: { price: 58000000, gift: "200 chai Siêu dưỡng trái" }
    };
    if (table[qty]) return table[qty];
    
    const keys = Object.keys(table).map(Number).sort((a,b)=>a-b);
    if (qty > keys[keys.length-1]) {
        const lastKey = keys[keys.length-1];
        const lastVal = table[lastKey];
        const multiplier = qty / lastKey;
        return {
            price: Math.floor(lastVal.price * multiplier),
            gift: `Tỉ lệ quy đổi theo số lượng: ${Math.floor(200 * multiplier)} chai Siêu dưỡng trái`
        };
    }
    let lowerKey = 1;
    let upperKey = 10;
    for (let k of keys) {
        if (k <= qty) lowerKey = k;
        if (k >= qty) {
            upperKey = k;
            break;
        }
    }
    const lowerVal = table[lowerKey];
    const upperVal = table[upperKey];
    const ratio = (qty - lowerKey) / (upperKey - lowerKey);
    const interpolatedPrice = lowerVal.price + ratio * (upperVal.price - lowerVal.price);
    return {
        price: Math.floor(interpolatedPrice),
        gift: `Xem quà tặng ở mốc gần nhất (${lowerKey} Thùng hoặc ${upperKey} Thùng)`
    };
}

